// Runs on the server. Returns a hardcoded user and persists the user info
// into PersistentComponentState so the WASM client can pick it up.
public sealed class ServerAuthenticationStateProvider : ServerAuthenticationStateProvider<ServerAuthenticationStateProvider>
{
}

public class ServerAuthenticationStateProvider<T> : AuthenticationStateProvider, IDisposable
    where T : ServerAuthenticationStateProvider<T>
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authStateTask;

    public ServerAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        if (_authStateTask is null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, "bob@example.com"),
                new(ClaimTypes.Email, "bob@example.com"),
                new(ClaimTypes.Role, "User"),
                new(ClaimTypes.Role, "Editor"),
            };

            var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
            _authStateTask = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }

        return _authStateTask;
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var userInfo = new UserInfo
            {
                Email = principal.FindFirst(ClaimTypes.Email)!.Value,
                Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
            };

            _persistentState.PersistAsJson(nameof(UserInfo), userInfo);
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

